const stack = [];
const lines = content.split('\n');
for (let i = 0; i < lines.length; i++) {
  let line = lines[i];

  // Quick and dirty string removal to avoid counting `{` in strings
  line = line.replace(/"[^"]*"/g, '""');
  line = line.replace(/'[^']*'/g, "''");
  line = line.replace(/`[^`]*`/g, "``");
  // Quick and dirty comment removal
  line = line.split('//')[0];

  for (let j = 0; j < line.length; j++) {
    const char = line[j];
    if (char === '{') {
      depth++;
      stack.push(i + 1);
    }
    if (char === '}') {
      depth--;
      stack.pop();
    }
  }
}
console.log('Unclosed blocks start at lines:', stack);

